# Инициализируем переменные в памяти (если их еще нет)
if 'current_step' not in st.session_state:
    st.session_state.current_step = 0
if 'score' not in st.session_state:
    st.session_state.score = 0
if 'answered' not in st.session_state:
    st.session_state.answered = False

# Основной экран
st.title("🚜 Тренажер: Один за другим")

# Проверяем, не закончились ли вопросы
if st.session_state.current_step < len(questions):
    item = questions[st.session_state.current_step]

    st.subheader(f"Вопрос {st.session_state.current_step + 1} из {len(questions)}")
    st.progress((st.session_state.current_step) / len(questions))  # Полоска прогресса
    st.write(item["q"])

    # Кнопки выбора (заблокированы, если уже ответил)
    choice = st.radio(
        "Выбери ответ:",
        item["options"],
        key=f"q_{st.session_state.current_step}",
        index=None,
        disabled=st.session_state.answered
    )

    # Логика после выбора
    if choice and not st.session_state.answered:
        st.session_state.answered = True
        if choice == item["answer"]:
            st.session_state.score += 1
            st.success("🎯 Правильно!")
        else:
            st.error(f"❌ Ошибка. Правильный ответ: {item['answer']}")

        st.info(f"💡 **Справка:** {item['explanation']}")

    # Кнопка "Далее" появляется только после ответа
    if st.session_state.answered:
        if st.button("Далее ➡️"):
            st.session_state.current_step += 1
            st.session_state.answered = False
            st.rerun()

else:
    # Финальный экран
    st.balloons()
    st.header("🏁 Тест пройден!")
    st.metric("Твой результат", f"{st.session_state.score} из {len(questions)}")

    if st.button("Начать сначала"):
        st.session_state.current_step = 0
        st.session_state.score = 0
        st.session_state.answered = False
        st.rerun()